const NEGATIVES = ["\"job\"","\"jobs\"","\"hiring\"","\"career\"","\"careers\"","\"salary\"","\"training\"","\"school\"","\"course\"","\"certification\"","\"license exam\"","\"how to\"","\"diy\"","\"youtube\"","\"reddit\"","\"manual\"","\"pdf\"","\"diagram\"","\"schematic\"","\"parts\"","\"part\"","\"replacement part\"","\"parts store\"","\"used\"","\"for sale\"","\"buy\"","\"home depot\"","\"lowes\"","\"best buy\"","\"costco\"","\"walmart\"","\"amazon\"","\"ebay\"","\"free\"","\"free appliance\"","\"warranty claim\"","\"recall\"","\"customer service\"","\"support phone number\"","\"samsung support\"","\"lg support\"","\"whirlpool support\"","\"ge support\"","\"maytag support\"","\"bosch support\"","\"kitchenaid support\"","\"frigidaire support\"","\"kenmore support\"","\"24 hour\"","\"24/7\"","\"emergency 24 hour\"","\"air conditioner\"","\"ac repair\"","\"hvac\"","\"furnace\"","\"plumbing\"","\"plumber\"","\"electrician job\"","\"tv repair\"","\"computer repair\"","\"phone repair\"","\"laptop repair\"","\"vacuum repair\"","\"sewing machine repair\"","\"car repair\"","\"auto repair\"","\"small engine repair\"","\"lawn mower repair\"","\"garage door\"","\"commercial refrigeration jobs\""];
const DAYS = ['MONDAY','TUESDAY','WEDNESDAY','THURSDAY','FRIDAY','SATURDAY','SUNDAY'];

function main() {
  ensureLabel();
  pauseOldCampaigns();
  createMissingCampaigns();
  Utilities.sleep(20000);
  configureCampaigns();
  createAdGroupsKeywordsAndAds();
  Logger.log('DONE. Campaigns are created/configured and remain paused. Review conversion tracking before enabling.');
}

function ensureLabel() {
  const labels = AdsApp.labels().withCondition("Name = '" + SETUP_LABEL.replace(/'/g, "\\'") + "'").get();
  if (!labels.hasNext()) {
    AdsApp.createLabel(SETUP_LABEL, 'Search campaigns created by Codex for appliance repair lead generation.', '#17437a');
  }
}

function pauseOldCampaigns() {
  OLD_CAMPAIGNS.forEach(function(name) {
    const c = getCampaignByName(name);
    if (c) {
      c.pause();
      try { c.applyLabel(SETUP_LABEL); } catch (e) {}
      Logger.log('Old campaign kept paused: ' + name);
    }
  });
}

function createMissingCampaigns() {
  const missing = CAMPAIGNS.filter(function(c) { return !getCampaignByName(c.name); });
  if (missing.length === 0) {
    Logger.log('No missing campaigns.');
    return;
  }
  const columns = ['Campaign', 'Budget', 'Bid Strategy type', 'Campaign type', 'EU political ads'];
  const upload = AdsApp.bulkUploads().newCsvUpload(columns, {moneyInMicros: false, timeZone: 'America/New_York'});
  missing.forEach(function(c) {
    upload.append({'Campaign': c.name, 'Budget': c.budget, 'Bid Strategy type': 'cpc', 'Campaign type': 'Search Only', 'EU political ads': 'No'});
  });
  upload.forCampaignManagement();
  upload.apply();
  Logger.log('Created campaign bulk upload for ' + missing.length + ' campaigns. If campaigns are not visible yet, run this script one more time.');
}

function configureCampaigns() {
  CAMPAIGNS.forEach(function(cfg) {
    const campaign = getCampaignByName(cfg.name);
    if (!campaign) {
      Logger.log('Campaign not ready yet: ' + cfg.name);
      return;
    }
    campaign.pause();
    try { campaign.applyLabel(SETUP_LABEL); } catch (e) {}
    try {
      campaign.addProximity({
        latitude: cfg.lat,
        longitude: cfg.lng,
        radius: cfg.radius,
        radiusUnits: 'MILES',
        address: {cityName: cfg.city, provinceCode: 'IN', countryCode: 'US'}
      });
      Logger.log('Added radius targeting for ' + cfg.city);
    } catch (e) {
      Logger.log('Location targeting skipped/exists for ' + cfg.city + ': ' + e.message);
    }
    DAYS.forEach(function(day) {
      try { campaign.addAdSchedule(day, 8, 0, 18, 0); } catch (e) {}
    });
    NEGATIVES.forEach(function(neg) {
      try { campaign.createNegativeKeyword(neg); } catch (e) {}
    });
  });
}

function createAdGroupsKeywordsAndAds() {
  AD_GROUPS.forEach(function(g) {
    const campaign = getCampaignByName(g.campaign);
    if (!campaign) return;
    campaign.pause();
    let adGroup = getAdGroupByName(campaign, g.name);
    if (!adGroup) {
      adGroup = campaign.newAdGroupBuilder().withName(g.name).withStatus('PAUSED').withCpc(g.cpc).build().getResult();
      Logger.log('Created ad group: ' + g.campaign + ' / ' + g.name);
    } else {
      adGroup.pause();
    }
  });

  const keywordsByGroup = groupBy(KEYWORDS, function(k) { return k.campaign + '||' + k.adGroup; });
  Object.keys(keywordsByGroup).forEach(function(key) {
    const first = keywordsByGroup[key][0];
    const campaign = getCampaignByName(first.campaign);
    if (!campaign) return;
    const adGroup = getAdGroupByName(campaign, first.adGroup);
    if (!adGroup) return;
    adGroup.pause();
    if (adGroup.keywords().get().hasNext()) return;
    keywordsByGroup[key].forEach(function(k) {
      try { adGroup.newKeywordBuilder().withText(k.text).withCpc(k.cpc).withFinalUrl(k.finalUrl).build(); } catch (e) { Logger.log('Keyword skipped: ' + k.text + ' - ' + e.message); }
    });
    Logger.log('Added keywords: ' + first.campaign + ' / ' + first.adGroup + ' = ' + keywordsByGroup[key].length);
  });

  ADS.forEach(function(a) {
    const campaign = getCampaignByName(a.campaign);
    if (!campaign) return;
    const adGroup = getAdGroupByName(campaign, a.adGroup);
    if (!adGroup) return;
    adGroup.pause();
    if (adGroup.ads().get().hasNext()) return;
    const headlines = a.headlines.slice(0, 12).map(function(h) { return String(h).substring(0, 30); });
    const descriptions = a.descriptions.slice(0, 4).map(function(d) { return String(d).substring(0, 90); });
    try {
      adGroup.newAd().responsiveSearchAdBuilder()
        .withHeadlines(headlines)
        .withDescriptions(descriptions)
        .withPath1(a.path1)
        .withPath2(a.path2)
        .withFinalUrl(a.finalUrl)
        .build();
      Logger.log('Created RSA: ' + a.campaign + ' / ' + a.adGroup);
    } catch (e) {
      Logger.log('RSA skipped: ' + a.campaign + ' / ' + a.adGroup + ' - ' + e.message);
    }
  });
}

function getCampaignByName(name) {
  const it = AdsApp.campaigns().get();
  while (it.hasNext()) {
    const c = it.next();
    if (c.getName() === name) return c;
  }
  return null;
}

function getAdGroupByName(campaign, name) {
  const it = campaign.adGroups().get();
  while (it.hasNext()) {
    const g = it.next();
    if (g.getName() === name) return g;
  }
  return null;
}

function groupBy(items, keyFn) {
  const out = {};
  items.forEach(function(item) {
    const key = keyFn(item);
    if (!out[key]) out[key] = [];
    out[key].push(item);
  });
  return out;
}

